	 (2,'EÜS X 1031 (403)','N','ERA, Fon. 100 b',NULL,NULL,1,1,1,NULL,'<Kontrollitud: T. O. Lisasilp, aga 8 pos, tõenäoliselt pika silbiga sõna tõttu, edaspidi aga tõenäoliselt tuleb 9 pos. Parandasin Kratsova - Krantsova. Määrasin rütmitüübi tavalises korras 2. 12.12.2020. Parandasin nüüd rütmitüübi vastavalt lisasilbi olemasolule, olles rohkem tegelenud setu lauludega. 2.01.2021. Salvestust võib olla kasutatud hiljem viisi täpsustamisel, seetõttu märkisin viisile ja noodistusele sama viite. 30.05.2021>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,3307,4208),
	 (2,'ERA III 1, 127 (2)','ERA II 21, 155/6','ERA, Fon. 258 a',NULL,'XII 358 / 364',1,1,1,NULL,'<Helisalvestus: Selge, lõpuosas mingi kahjustus. Märgitud: (Fon. N 1 a)> <Kontrollitud: T. O. Ilmselt on välitöödel tehtud noodistust hiljem fonogrammi järgi täpsustatud. Lisasin heli viite. Teksti juures on vanad fonogrammi numbrid. Koguja on teksti jaganud a ja b osaks, digiteerija on jaganud ka fonogrammi. Viisi viide kattub noodistuse viitega. 30.05.2021>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,194,4411),
	 (2,NULL,'ERA II 56, 420/1 (11)','ERA, Fon 371 b',NULL,'XIII 519',1,1,1,NULL,'<Helisalvestus: Kahiseb, kostab halvasti. Noodistatud on palju variatsioone, aga mitte kogu salvestust.> <Kontrollitud: T. O. Noodistus tehtud salvestuse põhjal. Noodi juures on vana fonogramminumber. Lisasin heli viite. 30.05.2021>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,443,1861),
