	 (2,'ERA III 1, 52 (96)','ERA II 6, 572/4 (18-22)',NULL,NULL,'II 386',1,1,1,NULL,'<Kontrollitud: T. O. Täiendasin andmeid. Ilmselt lauldi kogu mardilaulude tsükkel, mis siin on eri numbrite all, ühe viisiga. Eraldi viited on ERA II 6, 572 (18), 572/3 (19), 573 (20), 573/4 (21), 574 (22). Otsingu jaoks peaks nendest tegema eraldi viited? Rütm on pikendusega rõhulistel nootidel, märgitud punkteeritud noodiga, viimane takt erinev. Muutsin siin laulu nr 95 eeskujul rütmitüübi, mis enne oli 1. Kontrollisin üle 5.01.2021>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,244,440),
	 (2,'ERA III 1, 55 (104)','ERA II 6, 447 (1)',NULL,NULL,'VI 295, VI 255.1',1,1,1,NULL,'<Kontrollitud: T. O. Lisasin teksti viited (teise võtsin viisiduplikaadist), täiendasin esitaja andmeid. Laulmisel on silbid redutseerunud, võrreldes teksti üleskirjutusega - kas ehk tekst on kirjutatud dikteerimise järgi? VI 255 järel asendasin VI 255.1. 31.07.2020.>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,246,902),
	 (2,'ERA III 1, 84 (183)','ERA II 7, 51/2 (1, 2)',NULL,NULL,'II 336',1,1,1,NULL,'<Kontrollitud: T. O. 2019/20. Leidsin viisile teksti dSaati tekstikogu viidete põhjal. Vbl on sama viisiga ka ERA II 7, 443 (106), (108), 444 (110), kus on viisi nr puudu? Arvatavasti ekslikult on koguja siinse viisi nr-i märkinud tekstile ERA II 7, 444 (117). See hästi ei sobi ning tolle teksti jaoks on ka eraldi viis ERA III 1, 85 (189) (see pole 2-realine viis, tekst ise on uuem).>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,268,393),
	 (2,'ERA III 1, 58 (114)','ERA II 7, 419 (53)',NULL,NULL,'VIII 154',1,1,1,NULL,'<Kontrollitud: T. O. Siin on samal välitööl kogutud sama laulu praktiliselt kattuvad tekstivariandid (erinevus detailides) tehtud eri kirjeteks, eelmistel juhtudel mitte ERA III 1, 52 (93, 95, 96). Kas panna siin ka kokku? Vrdl ERA II 6, 427 (23)>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,249,2293),
	 (2,'ERA III 1, 43 (63)','ERA II 6, 173/4 (10)',NULL,NULL,'XV 334',1,1,1,NULL,'<Kontrollitud: T. O.>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,237,3822),
	 (2,'ERA III 1, 43 (64)','ERA II 6, 173 (9)',NULL,NULL,'XI 207',1,1,1,NULL,'<Kontrollitud: T. O. Arvatavasti viis ja tekst kirjutatud eri esituste järgi.>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,238,3166),
	 (2,'ERA III 1, 51 (89)','ERA II 6, 538 (1)',NULL,NULL,'X 98',1,1,1,NULL,'<Kontrollitud: T. O. Tekst kogus ja noodi all veidi erinevad. Teksti üleskirjutus võib olla dikteeritud, sest pole esitusega seotud lisasilpe märgitud. Täiendasin andmeid.>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,241,2881),
