	 (2,NULL,NULL,'RKM, Mgn. II 63 c',NULL,'XIV 118',1,1,1,NULL,'<Helisalvestus: Ilus. Helisalvestusele lähedane laulutekst on lauliku enda kirjutatud pulmakirjelduses.> <Kontrollitud: Lisasin teksti viite, tüübinime, esituse, parandasin lauliku nime, liigi, deš andmed. T. O. 13.07.2020>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,151,3434),
