	 (1,'RKM II 104, 382 (139)','RKM II 95, 538/9 (65)',NULL,NULL,'XI 350',1,1,1,NULL,NULL,NULL,NULL,3953,3253),
	 (2,'EÜS IX 1329 (208)','EÜS IX 1426/7 (2); EÜS IX 1522/3 (2, mustand)','ERA, Fon. 18 d',NULL,'IX 288',2,1,1,NULL,'<Helisalvestus: Fonogrammi pole, kuigi fonogrammi number ERA, Fon 018 d) on noodistuse juures> <Kontrollitud: T. O. Oli: Veera Kararenkova. Praegused eri nimekujud tulid viiside kogust ja nimekirjast. Parandasin rahvaks "vene", sest nii oli Väisänen märkinud. Kustutaksin helisalvestuse viite, sest salvestust ju ei ole. Teksti kogujana olid andmebaasis märgitud Nirk, A./Tamm, R., 1912/1913, kuid originaalis on ainult Tamm 1912, nii ka parandasin. Salvestust võib olla kasutatud hiljem viisi täpsustamisel, seetõttu märkisin viisile ja noodistusele sama viite. 30.05.2021>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,177,2709),
	 (2,NULL,'EStk 15, 37/8 (30)','ERA, Fon. 336 c',NULL,'IX 215',1,1,1,'Taive Särg "Karksi vanad rahvalaulud" 2008','<Kontrollitud: T. O. Fonogrammi tekst (litereering?) asub eraldi.30.05.2021>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,169,2654),
	 (2,'ERA III 6, 206 (55)',NULL,NULL,NULL,'X 295',1,1,1,NULL,'<Kontrollitud: T. O. Üks 11-silbiline värss, 9-11 positsiooni - see pole 2-realine viis. Rütmitüüp peab tulema L. Täpsustasin andmeid. 24.02.2021.>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,393,3040),
