	 (2,'EÜS IX 1347 (294)','EÜS IX 1503 (93)','ERA, Fon. 29 f',NULL,'II 343',1,1,1,NULL,'<Kontrollitud: T. O. Väisäse teksti veerisime välja koos Urmas Kallaga. 13.11.2020 Salvestust võib olla kasutatud hiljem viisi täpsustamisel, seetõttu märkisin viisile ja noodistusele sama viite. 30.05.2021>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,181,402),
	 (2,'EÜS IX 1366 (387)',NULL,'ERA, Fon. 44 b',NULL,'XV 265',1,1,1,NULL,'<Kontrollitud: T. O. Noodistuse järgi see ei ole 2-realine viis: siin on 1 värss, kus esimest sõna korratakse või varieeritakse, seega on siin kokku 10 positsiooni. Helisalvestuse järgi on see 1-realine viis: gahh ah ggfisfis. Enne oli algusvärss: Kun ma kuna nakkan laulemahe- - - Salvestust võib olla kasutatud hiljem viisi täpsustamisel, seetõttu märkisin viisile ja noodistusele sama viite. 30.05.2021>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,183,3778),
	 (1,'EÜS VIII 2514 (72)','EÜS VIII 1819 (45)',NULL,NULL,'XIII 422',1,1,1,NULL,'<Kontrollitud: M.O parandasin tekstiviite: oli EÜS VIII 1815j. (45); lisasin algusvärsi 24.07.21>',NULL,NULL,2724,1622),
	 (2,'ERA III 1, 135 (20)','ERA III 136/7 (28)','ERA, Fon. 268 a, b',NULL,'VIII 251',1,1,1,NULL,'<Helisalvestus: Selge, ilus, tekstist erinev variant.> <Kontrollitud: T. O. See on järjekindel 4-realine viis, ei kuulu siia. Tekst ja noot ei vasta helile, mis on pikem ja lauldakse teise struktuuriga. Lisasin teksti viite, vormi. Noodi ja teksti juures vanad fonogramminumbrid. Viisi viide kattub noodistuse viitega. 30.05.2021>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,205,2404),
	 (1,'ERA II 82, 701 (1)',NULL,NULL,NULL,'67',1,1,1,NULL,'<Kontrollitud: Täpsustasin kogujat, muutsin värsivormi. Muu vaatamata. 13.08.2020.>',NULL,NULL,141,4019),
	 (2,'RKM III 5, 85 (67)',NULL,NULL,NULL,'54',1,1,1,NULL,'<Kontrollitud: T. O. Uuem lõppriimiline laul. Rütmitüüp OK. 2.01.2021>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,4373,3999),
	 (2,'ERA III 1, 337','ERA II 21, 161/2 (3)','ERA, Fon. 260 a',NULL,'X 270',1,1,1,NULL,'<Helisalvestus: Salvestusel kaks varianti: kiirem, segasem (lühike) ja aeglasem, selgem (pikem). Arusaadav. Noodi juures heli kohta: "rulli algus, hiljem segane", teksti juures: "kiirus 2/3, endise 1/4 asemel, fonogr. nõrk".> <Kontrollitud: T. O. Noodistatud fonogrammi järgi, aga pole täpne. Lisasin teksti viite. Viisi viide kattub noodistuse viitega. 30.05.2021>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,229,3020),
