	 (2,'EÜS VIII 166 (18)','EÜS VIII 166 (18)',NULL,NULL,NULL,2,1,1,NULL,'<Kontrollitud: T. O.; M. O. See oli siinsest üldosa tabelist puudu, lisasin. Origin-s on topelt numeratsioon, teine nr 92. T. 28.04.2021; 12.07.2021. Parandasin: esitaja rahvuse (oli eesti), heliilatuse (oli 3s). Tõstsin nime Palaga küla nimest isikunimeks. M. Parandasin rütmitüübi. T. 20.08.2021>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,2663,2855),
