	 (2,'ERA III 1, 137 (29)','ERA II 21, 195/7 (40)','ERA, Fon. 266 c',NULL,'VIII 159',1,1,1,NULL,'<Helisalvestus: Selge, ilus, tekstist ja noodist veidi erinev variant.> <Kontrollitud: T. O. Lisasin teksti viite, esitaja nime ja andmed. Tekst ja heli/noot eri variandid (2 või 3), heli on noodist pikem, aga noodi variatsiooni pole mujal. Noodi ja teksti juures vanad fonogramminumbrid.>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,145,2298),
	 (2,'ERA III 1, 84 (183)','ERA II 7, 444 (112) / ERA II 7, 53 (4)',NULL,NULL,NULL,1,1,1,NULL,'<Kontrollitud: T. O. 2019/20. Leidsin viisile tekstid Saati tekstikogu viidete põhjal. Vbl on sama viisiga ka ERA II 7, 443 (106), (108), 444 (110), kus on viisi nr puudu? Arvatavasti ekslikult on koguja siinse viisi nr-i märkinud tekstile ERA II 7, 444 (117). See hästi ei sobi ning tolle teksti jaoks on ka eraldi viis ERA III 1, 85 (189) (see pole 2-realine viis, tekst ise on uuem).>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,274,8026),
	 (2,'ERA III 1, 84 (183)','ERA II 7, 444 (111)',NULL,NULL,NULL,1,1,1,NULL,'<Kontrollitud: T. O. 2019/20. Leidsin viisile tekstid Saati tekstikogu viidete põhjal. Vbl on sama viisiga ka ERA II 7, 443 (106), (108), 444 (110), kus on viisi nr puudu? Arvatavasti ekslikult on koguja siinse viisi nr-i märkinud tekstile ERA II 7, 444 (117). See hästi ei sobi ning tolle teksti jaoks on ka eraldi viis ERA III 1, 85 (189) (see pole 2-realine viis, tekst ise on uuem).>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,273,8025),
