	 (2,'ERA III 6, 187 (18)','ERA II 35, 182/7 (5)','ERA, Fon 340 a',NULL,'411',1,1,1,NULL,'<Helisalvestus: selge, 4 värssi> <Kontrollitud: T. O. Laul algab eeltaktiga ja lõppeb 7-silbilise reaga, näeb UL moodi välja. Noodistus vastab pigem 3.-4. värsile. Lisasin heli ja teksti viite. Leichter võis viisi üles kirjutada välitöödel ja hiljem üle noodistada helisalvestuse põhjal. Seetõttu viisi ja (helisalvestuse) noodistuse viide on samad. Ktr litereerimise andmeid, aastat. 30.05.2021>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,389,4053),
	 (2,'EÜS VIII 184 (123)','N',NULL,NULL,'248a',1,1,1,NULL,'<Kontrollitud: Kogus on topelt numeratsioon, teine nr. 197. Otsida sõnu EÜS-i kogust, A. Sibula saadetis. 4-realine viis. Täpsustasin kogujad, koha, algusvärsi. T. O. 4.08.2020; 12.07.2021>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,2670,4104),
	 (2,'EÜS X 1096 (533)','EÜS X 1096 (533)','ERA, Fon. 118 f',NULL,'II 214',1,1,1,NULL,'<Kontrollitud: T. O See kirje on topelt, kahte teksti või muud põhjust pole näha. Teine viisi nr oli 369, kustutan selle. Viiside osas on nr 369 kodeeritud ilma variatsioonideta. 12.12.2020 Rütmitüübi märkisin 1. Salvestust võib olla kasutatud hiljem viisi täpsustamisel, seetõttu märkisin viisile ja noodistusele sama viite. 30.05.2021.>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,3322,4574),
	 (1,'RKM II 64, 509 (171)','N',NULL,NULL,'XV 194',1,1,1,NULL,NULL,NULL,NULL,4174,3745),
	 (2,NULL,NULL,'RKM, Mgn. II 1239 a',NULL,'435',1,1,1,NULL,'<Helisalvestus: Laulab 2 korda ja ütleb, kellelt õpitud.> <Kontrollitud: Pole 2-realine viis, vaid refrääniline stroofilaande. Parandasin kogumise andmeid Kivikese ja kuulamise järgi. RÜtmitüüp oli 1, märkisin lihtsalt, et refrääniga. T. O. 9.08.2020>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,4385,4055),
	 (2,'ERA III 2, 341 (319)','ERA II 17, 833 / ERA II 17, 838',NULL,NULL,'XIV 800',1,1,1,NULL,'<Kontrollitud: T. O. Sama algusvärsiga on tekstikogus kaks laulu lk 833 ja 838. Minu eelkäija on märkinud viiside ja tekstide seosed järgmiselt, samas ma ei näe põhjendust: ERA III 2, 341 (318) - ERA II 17, 838; ERA III 2, 341 (319) ja (320) - ERA II 17, 831. Pealegi ei ole 831 üldse regivärsiline. Muutsin siin oma arvamust mööda.>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,306,3640),
