	 (2,'EÜS IX 1329 (210)','EÜS IX 1466 (54)','ERA, Fon. 18 e',NULL,'XI 196',2,1,1,NULL,'<Helisalvestus: Fonogrammi pole, kuigi fonogrammi number ERA, Fon 018 e) on noodistuse juures> <Kontrollitud: T. O. Oli Veera Karasenkova. Praegused eri nimekujud on viiside juures ja nimekirjas. Pole päris järjekindel 2-realisus. Kustutaksin helisalvetuse viite, sest salvestust ju ei ole. Teksti ehitus: ABRB, leidub lõppriimi. Salvestust võib olla kasutatud hiljem viisi täpsustamisel, seetõttu märkisin viisile ja noodistusele sama viite. 30.05.2021>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,178,3158),
