	 (2,'ERA III 6, 251 (180)','ERA II 36, 233/4 (1)','ERA, Fon. 352 b',NULL,'IX 248',1,1,1,NULL,'<Helisalvestus: Enam-vähem. Tekst on kirjutatud teise variandi järgi.> <Kontrollitud: T. O. Parandasin esitaja Latui??. Viisi juurde on originaalis märgitud vale esitaja, samuti on viga viiside ja fonogrammide registris - Juhan Latik. Noot vastab fonogrammile ja sealt kuuleb selgesti, et naine laulab, ja sama variandi tekst on tekstikogus naise nimega. Leichter võis viisi üles kirjutada välitöödel ja hiljem üle noodistada helisalvestuse põhjal. Seetõttu viisi ja noodistuse viide on samad. 30.05.2021>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,412,2679),
