	 (2,'ERA III 6, 188 (21)','ERA II 35, 191 (9)','ERA, Fon. 340 e',NULL,'IX 360',1,1,1,NULL,'<Helisalvestus: helisalvestus on ilmselt tehtud teise esitusvariandi järgi kui viis, selge> <Kontrollitud: T. O. Noodistus ei kattu täpselt salvestusega, tehtud ilmselt salvestamata esituse põhjal. Lisasin heli viite. Leichter võis viisi üles kirjutada välitöödel ja hiljem üle noodistada helisalvestuse põhjal. Ktr litereerimise andmeid, aastat. 30.05.2021>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,390,2749),
