	 (1,'KKI 10, 696 (3)','KKI 10, 431/3 (17) / KKI 10, 554/6 (17)',NULL,NULL,'V 85',1,1,1,'Vana Kannel V, lk 165, nr 277',NULL,NULL,NULL,3829,714),
	 (2,'ERA III 2, 13 (4)','ERA II 17, 80/4, 84/9 (41)','ERA, Fon. 211 a1, a2',NULL,'IV 425',1,1,1,NULL,'<Helisalvestus: a1) Kehv, tekst mõistetav üleskirjutuse abil. Noot ja heli arvatavalt eri esituste järgi. Helisalvestuse värsid, võrreldes noodi ja tekstiga, osalt kattuvad, osalt erinevad ja teises järjekorraas. Noodis ja tekstis on värsse, mida salvestusel ei ole. a2) Lühem ja halvem salvestus, ei saa sõnadest aru.> <Kontrollitud: T. O. Esituse kohta oli andmebaasis märgitud E+Ü ehk kahekesi, kuid see oli ilmselt nime ja hüüdnime vale tõlgendamine, helisalvestusel laulis üks inimene ja pole vihjeid 2 naise kohta. Parandasin. Noot ei ole tehtud arvatavasti nende salvestuste järgi.>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,283,606),
	 (2,'ERA III 2, 337 (314)','ERA II 17, 821 (27)',NULL,NULL,'X 183',1,1,1,NULL,'<Kontrollitud: T. O. Lisasin teksti viite. Eelkäija on määranud laulutüübiks "Kubjas põrgus", ma panin küsimärgi, sest ei näe selle põhjust.>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,303,2930),
	 (1,'EÜS VI 888 (67)','EÜS VI 980 (129)',NULL,NULL,'IX 69',1,1,1,NULL,'<Kontrollitud: Rütmit OK. 10.12.2020 T.O.>',NULL,NULL,1814,2589),
	 (2,'ERA III 2, 45 (33)','ERA II 17, 122/3 (66a)','ERA, Fon. 215 c',NULL,'II 396',1,1,1,NULL,'<Helisalvestus: Selge salvestus, viisikäik ja laulutekst erinevad noodist - pole sama variant. Heli ja tekst natuke erinevad.> <Kontrollitud: T. O. Ilmselt pole heli järgi noodistatud. Fonograafil on viis ERA III 2, 43 (32) mardilaulu sõnadega. Sellele viitab ka koguja märkus mardilaulu juures: "Lauldud ka viisil nr 32". Siin noodistatud mardilaulu viisi pole aga salvestatud, seega viisi poolest kuulub salvestus pigem teise laulu juurde või on eraldi variant. Vbl laulja esitas kaks korda eri viisidega. Kas tekstiosale võiks lisada (a).>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,311,446),
	 (1,'KKI 10, 698 (8)','KKI 10, 441/2 (23) / KKI 10, 563/4 (23)',NULL,NULL,'VIII 221',1,1,1,'Vana Kannel V, lk 273, nr 483',NULL,NULL,NULL,3831,2372),
	 (2,NULL,NULL,'ERA, Pl. 28 A2',NULL,'XV 486',1,1,1,NULL,'<Helisalvestus: Selge ja ilus> <Kontrollitud: T. O. Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja ümberkirjutus. Parandasin viisi vormi, laululiigi (oli lüürika). Viis on varieeruv 1-realine, ei kuulu siia tabelisse. 21.02.2019>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,467,4006),
	 (2,NULL,NULL,'ERA, Pl. 28 A3',NULL,'XV 487',1,1,1,NULL,'<Helisalvestus: Selge ja ilus> <Kontrollitud: T. O. Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja ümberkirjutus (RKM III 4). Parandasin viisi vormi, laululiigi (oli lüürika). 21.02.2019>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,468,4007),
	 (2,NULL,NULL,'ERA, Pl. 20 B3',NULL,'XV 470',1,1,1,NULL,'<Helisalvestus: Selge ja ilus> <Kontrollitud: T. O. Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud tekstiga (?) ümberkirjutus (RKM III 4). Kaart vastab mustandile, üsna hea noodistus. Lisasin laulutüübi. 21.02.2019>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,463,3959),
	 (2,'ERA III 1, 130 (5)','ERA II 21, 170 (11)','ERA, Fon. 262 b',NULL,'I 571',1,1,1,NULL,'<Helisalvestus: Selge, tekstist ja noodist pikem> <Kontrollitud: T. O. Lisasin ka midagi (teksti viite?) Noodi ja teksti juures vanad fonogramminumbrid.>','2a70be90-2c43-4d25-8a3f-4a35de35b0de',NULL,198,189),
